class Solution {
    public int maxSatisfied(int[] customers, int[] grumpy, int minutes) {
        int n = customers.length;
        int total = 0;
        int maxSatisfied = 0;
        int windowSum = 0;

        for (int i = 0; i < n; i++) {
            if (grumpy[i] == 0) {
                total += customers[i];
            }
            if (i >= minutes) {
                windowSum -= customers[i - minutes];
            }
            if (i >= minutes - 1) {
                windowSum += customers[i];
                maxSatisfied = Math.max(maxSatisfied, windowSum);
            }
        }

        return total + maxSatisfied;
    }
}
```

